SELECT COUNT(DISTINCT s.pk_siape) AS quantidade FROM servidor s INNER JOIN calc_hora_aula_media c ON c.siape = s.pk_siape WHERE LOWER(s.area_ingresso) LIKE LOWER('%libras%') AND LOWER(s.categoria) = LOWER('docente') AND LOWER(s.contrato) = LOWER('efetivos') AND LOWER(c.sigla_campus) = LOWER('jat') AND c.ano = 2022 AND c.semestre = 1 AND (s.saiu_do_ifg = FALSE OR s.saiu_do_ifg IS NULL)